// Determine classification method for each email
const items = $input.all();
const tenantId = items[0]?.json?.tenant_id || '';
const results = [];

for (const item of items) {
  const email = item.json;
  let method = 'claude_haiku'; // default
  let skipAI = false;
  let classification = null;
  let confidence = 0;
  let senderType = 'unknown';
  let isUrgent = false;
  let isAutomated = false;

  // Fast path: sender pattern match with high confidence
  if (email.sender_class && parseFloat(email.sender_confidence) >= 0.9) {
    method = 'sender_pattern';
    classification = email.sender_class;
    confidence = parseFloat(email.sender_confidence);
    skipAI = true;
    isAutomated = true;

    // Determine sender type from classification
    if (['job_alert', 'marketing'].includes(classification)) senderType = 'job_board';
    else if (classification === 'recruiter_outreach') senderType = 'recruiter';
    else if (classification === 'not_job_related') senderType = 'unknown';
  }

  // Subject heuristic check for non-pattern-matched emails
  if (!skipAI) {
    const subject = (email.subject || '').toLowerCase();

    // Interview invitation patterns
    if (subject.match(/interview\s+(invitation|invite|request|schedule|confirmation)/i) ||
        subject.match(/invit(e|ation)\s+to\s+interview/i)) {
      classification = 'interview_invite';
      confidence = 0.88;
      method = 'subject_heuristic';
      isUrgent = true;
      skipAI = true;
    }
    // Rejection patterns
    else if (subject.match(/unfortunately|unsuccessful|not been selected|regret to inform/i) ||
             subject.match(/your application.*(?:update|status)/i) && subject.match(/unable|not|regret/i)) {
      classification = 'rejection';
      confidence = 0.86;
      method = 'subject_heuristic';
      skipAI = true;
    }
    // Offer patterns
    else if (subject.match(/offer of employment|job offer|offer letter|conditional offer/i)) {
      classification = 'offer';
      confidence = 0.85;
      method = 'subject_heuristic';
      isUrgent = true;
      // Still send to Claude for confirmation since offers are high-stakes
      skipAI = false;
    }
  }

  results.push({
    json: {
        tenant_id: tenantId,
      ...email,
      classification_method: method,
      skip_ai: skipAI,
      preliminary_classification: classification,
      preliminary_confidence: confidence,
      sender_type: senderType,
      is_urgent: isUrgent,
      is_automated: isAutomated
    }
  });
}

return results;

