BEGIN;
INSERT INTO email_classifications (tenant_id, email_id, classification, confidence, rationale,
    is_urgent, is_automated, sender_type,
    classification_method, classified_at) VALUES ('{{ $('Loop Over Tenants').item.json.tenant_id }}', '{{ $json.id }}'::uuid,
    '{{ $json.preliminary_classification }}',
    {{ $json.preliminary_confidence }},
    'Classified via {{ $json.classification_method }}: {{ $json.sender_source || $json.classification_method }}',
    {{ $json.is_urgent }},
    {{ $json.is_automated }},
    '{{ $json.sender_type }}',
    '{{ $json.classification_method }}',
    NOW()
)
ON CONFLICT (email_id) DO NOTHING;

UPDATE emails SET
    status = 'classified',
    classified_at = NOW(),
    is_job_related = {{ $json.preliminary_classification !== 'not_job_related' && $json.preliminary_classification !== 'marketing' }}
WHERE id = '{{ $json.id }}'::uuid;
COMMIT;

