// Parse Claude Haiku classification response
const input = $input.first().json;
const emailData = $('Classify: Triage').item.json;

let classification = 'not_job_related';
let confidence = 0.5;
let isUrgent = false;
let isAutomated = false;
let senderType = 'unknown';
let rationale = 'Parse error';
let inputTokens = 0;
let outputTokens = 0;
let needsEscalation = false;

try {
  // Handle API error
  if (input.statusCode && input.statusCode !== 200) {
    throw new Error(`Claude API returned ${input.statusCode}`);
  }

  const body = input.body || input;
  inputTokens = body.usage?.input_tokens || 0;
  outputTokens = body.usage?.output_tokens || 0;

  // Extract text content from Claude response
  const content = body.content?.[0]?.text || '';

  // Parse JSON from response (handle markdown code blocks)
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    classification = parsed.classification || 'not_job_related';
    confidence = parseFloat(parsed.confidence) || 0.5;
    isUrgent = parsed.is_urgent || false;
    isAutomated = parsed.is_automated || false;
    senderType = parsed.sender_type || 'unknown';
    rationale = parsed.rationale || '';
  }

  // Safety escalation check
  // Escalate offers to Sonnet for confirmation
  if (classification === 'offer') {
    needsEscalation = true;
  }
  // Low confidence -> escalate
  if (confidence < 0.80) {
    needsEscalation = true;
  }
  // Check for contextual offer phrases that Haiku might have missed
  const bodyText = (emailData.body_stripped || '').toLowerCase();
  const offerPhrases = [
    "we'd like to offer you",
    "offer of employment",
    "pleased to offer",
    "your offer letter",
    "annual salary of"
  ];
  if (classification !== 'offer' && offerPhrases.some(p => bodyText.includes(p))) {
    needsEscalation = true;
  }
} catch (err) {
  rationale = `Classification error: ${err.message}`;
  needsEscalation = false; // Don't escalate on API errors
}

// Estimate cost (Haiku: ~$0.25/M input, ~$1.25/M output)
const costUsd = (inputTokens * 0.25 / 1000000) + (outputTokens * 1.25 / 1000000);

return [{
  json: {
    email_id: emailData.id,
    email_subject: emailData.subject,
    email_from: emailData.from_email,
    gmail_thread_id: emailData.gmail_thread_id,
    body_stripped: emailData.body_stripped,
    snippet: emailData.snippet,
    classification,
    confidence,
    is_urgent: isUrgent,
    is_automated: isAutomated,
    sender_type: senderType,
    rationale,
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    cost_usd: costUsd,
    needs_escalation: needsEscalation,
    haiku_classification: classification,
    haiku_confidence: confidence
  }
}];

